#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int *A = (int*)malloc(N*sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        while (Q--) {
            int type, x;
            scanf("%d %d", &type, &x);
            if (type == 1) {
                N++;
                A = (int*)realloc(A, N*sizeof(int));
                A[N-1] = x;
                qsort(A, N, sizeof(int), compare);
            } else {
                for (int i = 0; i < N; i++) {
                    if (A[i] == x) {
                        for (int j = i; j < N-1; j++) {
                            A[j] = A[j+1];
                        }
                        N--;
                        A = (int*)realloc(A, N*sizeof(int));
                        break;
                    }
                }
            }
            if (N < 2) {
                printf("0\n");
            } else {
                int sum = 0;
                for (int i = 0; i < N-1; i++) {
                    sum += abs(A[i] - A[i+1]);
                }
                printf("%d\n", sum);
            }
        }
        free(A);
    }
    return 0;
}

