import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            while (Q-- > 0) {
                int type = sc.nextInt();
                int x = sc.nextInt();
                if (type == 1) {
                    N++;
                    int[] temp = new int[N];
                    for (int i = 0; i < N-1; i++) {
                        temp[i] = A[i];
                    }
                    temp[N-1] = x;
                    A = temp;
                    Arrays.sort(A);
                } else {
                    for (int i = 0; i < N; i++) {
                        if (A[i] == x) {
                            for (int j = i; j < N-1; j++) {
                                A[j] = A[j+1];
                            }
                            N--;
                            int[] temp = new int[N];
                            for (int j = 0; j < N; j++) {
                                temp[j] = A[j];
                            }
                            A = temp;
                            break;
                        }
                    }
                }
                if (N < 2) {
                    System.out.println(0);
                } else {
                    int sum = 0;
                    for (int i = 0; i < N-1; i++) {
                        sum += Math.abs(A[i] - A[i+1]);
                    }
                    System.out.println(sum);
                }
            }
        }
    }
}

