const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, Q] = readline().split(' ').map(Number);
    const A = readline().split(' ').map(Number).sort((a, b) => a - b);
    for (let j = 0; j < Q; j++) {
        const [type, x] = readline().split(' ').map(Number);
        if (type === 1) {
            A.push(x);
            A.sort((a, b) => a - b);
        } else {
            const index = A.indexOf(x);
            A.splice(index, 1);
        }
        if (A.length < 2) {
            console.log(0);
        } else {
            let sum = 0;
            for (let k = 0; k < A.length - 1; k++) {
                sum += Math.abs(A[k] - A[k + 1]);
            }
            console.log(sum);
        }
    }
}

